async function main() {
  let count = 0;
  let fails = [];
  const results = [];
  for (const item of updates) {
    try {
      await prisma.product.update({
        where: { slug: item.slug },
        data: {
          description: item.description,
          metaDescription: item.metaDescription
        }
      });
      const wc = item.description.split(/\s+/).length;
      const mc = item.metaDescription.length;
      results.push({ slug: item.slug, words: wc, metaLen: mc });
      count++;
      console.log(`OK: ${item.slug} (${wc} words, meta ${mc} chars)`);
    } catch (e) {
      console.log('SKIP:', item.slug, e.message.substring(0, 80));
      fails.push(item.slug);
    }
  }
  console.log(`\nUpdated: ${count}/${updates.length}`);
  if (fails.length) console.log('Failed:', fails.join(', '));
  console.log('\n--- Summary ---');
  for (const r of results) {
    const ok = r.words >= 250 && r.metaLen >= 130 && r.metaLen <= 155;
    console.log(`${ok ? '✅' : '❌'} ${r.slug}: ${r.words} words, meta ${r.metaLen} chars`);
  }
}

main().then(() => prisma.$disconnect()).catch(e => { console.error(e); prisma.$disconnect(); });
